// Validate input from claude.ai chat
const SECRET = '3NuJfuJsMUFGonDnPESfiO5H5aLVBu1cqKl_-YcXS0c';
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};

// Auth check
if (headers['x-webhook-secret'] !== SECRET) {
  throw new Error('Unauthorized: invalid or missing X-Webhook-Secret header');
}

// Required fields
const required = ['summary', 'details', 'type', 'importance', 'project'];
for (const f of required) {
  if (body[f] === undefined || body[f] === null || body[f] === '') {
    throw new Error(`Missing required field: ${f}`);
  }
}

// Enum validation
const validTypes = ['Decision', 'Learning', 'Error', 'Insight', 'Pattern', 'Fact', 'Drift'];
if (!validTypes.includes(body.type)) {
  throw new Error(`Invalid type. Must be one of: ${validTypes.join(', ')}`);
}

const validProjects = ['TJ', 'TM', 'CL', 'CF', 'Ops', 'Personal'];
if (!validProjects.includes(body.project)) {
  throw new Error(`Invalid project. Must be one of: ${validProjects.join(', ')}`);
}

const importance = parseInt(body.importance);
if (isNaN(importance) || importance < 1 || importance > 5) {
  throw new Error('importance must be integer 1-5');
}

// Tags handling
let tags = body.tags;
if (!Array.isArray(tags)) {
  tags = tags ? [String(tags)] : [];
}
tags = tags.filter(t => t && typeof t === 'string').map(t => t.trim()).filter(Boolean);

return [{
  json: {
    summary: String(body.summary).trim(),
    details: String(body.details).trim(),
    type: body.type,
    importance: importance,
    project: body.project,
    tags: tags,
    source: 'ClaudeAi'
  }
}];

const mem = $('Validate Input').item.json;
const embedding = $json.data[0].embedding;
return [{ json: { ...mem, embedding } }];

const similarResults = $input.first().json;
const prev = $('Merge Embedding').item.json;

const hasSimilar = Array.isArray(similarResults) && similarResults.length > 0 && similarResults[0]?.id;

if (hasSimilar) {
  return [{ json: { action: 'update', existingId: similarResults[0].id, similarity: similarResults[0].similarity, ...prev } }];
} else {
  return [{ json: { action: 'insert', ...prev } }];
}

const result = $input.first().json;
const upstream = $('Decide Upsert').item.json;

const row = Array.isArray(result) ? result[0] : result;

return [{
  json: {
    success: true,
    action: upstream.action,
    id: row?.id || upstream.existingId || null,
    summary: upstream.summary,
    project: upstream.project,
    source: 'ClaudeAi',
    similarity: upstream.similarity || null
  }
}];

const item = $input.first().json;

const body = JSON.stringify({
  query_embedding: item.embedding,
  similarity_threshold: 0.85,
  filter_project: item.project
});

const SUPABASE_KEY = '***REDACTED***';

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://apfngqcnjdfinqwefzcs.supabase.co/rest/v1/rpc/find_similar_memory',
  headers: {
    'apikey': SUPABASE_KEY,
    'Authorization': `Bearer ${SUPABASE_KEY}`,
    'Content-Type': 'application/json'
  },
  body: body,
  json: true,
  returnFullResponse: false
});

const similarResults = Array.isArray(response) ? response : [];
const hasSimilar = similarResults.length > 0 && similarResults[0]?.id;

if (hasSimilar) {
  return [{ json: { action: 'update', existingId: similarResults[0].id, similarity: similarResults[0].similarity, ...item } }];
} else {
  return [{ json: { action: 'insert', ...item } }];
}

